#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int N, M;
    cin >> N >> M;
    vector<array<long long,3>> edges(M);
    for (int i = 0; i < M; i++) {
        long long u, v, w;
        cin >> u >> v >> w;
        edges[i] = {u, v, w};
    }
    const long long INF = (long long)1e18;
    vector<long long> dist(N + 1, INF);
    dist[1] = 0;
    for (int iter = 0; iter < N - 1; iter++) {
        for (auto& e : edges) {
            long long u = e[0], v = e[1], w = e[2];
            if (dist[u] == INF) continue;
            if (dist[u] + w < dist[v]) dist[v] = dist[u] + w;
        }
    }
    // 한 번 더 돌려 음수 사이클 영향 정점 표시
    vector<bool> neg(N + 1, false);
    for (int iter = 0; iter < N; iter++) {
        for (auto& e : edges) {
            long long u = e[0], v = e[1], w = e[2];
            if (dist[u] == INF) continue;
            if (dist[u] + w < dist[v] || neg[u]) {
                dist[v] = dist[u] + w;
                neg[v] = true;
            }
        }
    }
    bool anyNeg = false;
    for (int i = 1; i <= N; i++) if (neg[i]) anyNeg = true;
    if (anyNeg) {
        cout << -1 << "\n";
        return 0;
    }
    for (int i = 2; i <= N; i++) {
        if (dist[i] == INF) cout << -1 << "\n";
        else cout << dist[i] << "\n";
    }
    return 0;
}
